// MARK: - Secure Storage

final class SecureStorageService {
    
    static let shared = SecureStorageService()
    private let encryption = EncryptionService.shared
    private let fileManager = FileManager.default
    
    private var storageDirectory: URL {
        let documentsDir = fileManager.urls(for: .documentDirectory, in: .userDomainMask).first!
        let secureDir = documentsDir.appendingPathComponent("SecureStorage", isDirectory: true)
        if !fileManager.fileExists(atPath: secureDir.path) {
            try? fileManager.createDirectory(at: secureDir, withIntermediateDirectories: true)
        }
        return secureDir
    }
    
    private init() {}
    
    func save<T: Codable>(_ model: T, forKey key: String) throws {
        let encryptedData = try encryption.encryptModel(model)
        let fileURL = storageDirectory.appendingPathComponent(key)
        try encryptedData.write(to: fileURL, options: [.atomic, .completeFileProtection])
    }
    
    func load<T: Codable>(forKey key: String, as type: T.Type) throws -> T {
        let fileURL = storageDirectory.appendingPathComponent(key)
        let encryptedData = try Data(contentsOf: fileURL)
        return try encryption.decryptModel(encryptedData, as: type)
    }
    
    func delete(forKey key: String) throws {
        let fileURL = storageDirectory.appendingPathComponent(key)
        if fileManager.fileExists(atPath: fileURL.path) {
            try fileManager.removeItem(at: fileURL)
        }
    }
    
    func exists(forKey key: String) -> Bool {
        let fileURL = storageDirectory.appendingPathComponent(key)
        return fileManager.fileExists(atPath: fileURL.path)
    }
}

// MARK: - Transaction Validation

struct TransactionValidator {
    
    enum ValidationError: Error, LocalizedError {
        case insufficientFunds(available: Decimal, requested: Decimal)
        case invalidAmount
        case accountInactive
        case sameAccountTransfer
        case dailyLimitExceeded(limit: Decimal)
        case invalidAccount
        
        var errorDescription: String? {
            switch self {
            case .insufficientFunds(let available, let requested):
                return "Insufficient funds. Available: \(available), Requested: \(requested)"
            case .invalidAmount:
                return "Transaction amount must be greater than zero"
            case .accountInactive:
                return "Account is inactive"
            case .sameAccountTransfer:
                return "Cannot transfer to the same account"
            case .dailyLimitExceeded(let limit):
                return "Daily transaction limit of \(limit) exceeded"
            case .invalidAccount:
                return "Invalid account"
            }
        }
    }
    
    private static let dailyTransactionLimit: Decimal = 50000.00
    
    static func validate(transaction: Transaction, account: Account, allAccounts: [Account]) -> Result<Void, ValidationError> {
        guard account.isActive else {
            return .failure(.accountInactive)
        }
        
        guard transaction.amount > 0 else {
            return .failure(.invalidAmount)
        }
        
        if transaction.type == .transfer {
            guard let toAccountId = transaction.toAccountId else {
                return .failure(.invalidAccount)
            }
            guard toAccountId != transaction.fromAccountId else {
                return .failure(.sameAccountTransfer)
            }
            guard allAccounts.contains(where: { $0.id == toAccountId && $0.isActive }) else {
                return .failure(.invalidAccount)
            }
        }
        
        if transaction.type == .withdrawal || transaction.type == .transfer || transaction.type == .payment {
            guard account.balance >= transaction.amount else {
                return .failure(.insufficientFunds(available: account.balance, requested: transaction.amount))
            }
        }
        
        let todayTransactions = account.transactions.filter { transaction in
            Calendar.current.isDateInToday(transaction.timestamp) && transaction.status == .completed
        }
        let todayTotal = todayTransactions.reduce(Decimal.zero) { $0 + $1.amount }
        guard todayTotal + transaction.amount <= dailyTransactionLimit else {
            return .failure(.dailyLimitExceeded(limit: dailyTransactionLimit))
        }
        
        return .success(())
    }
}

