            entries = loaded
        }
    }
    
    func log(action: String, accountId: String, transactionId: String? = nil, details: String) {
        queue.async { [weak self] in
            guard let self = self else { return }
            let entry = AuditEntry(
                id: UUID(),
                timestamp: Date(),
                action: action,
                accountId: accountId,
                transactionId: transactionId,
                details: details,
                ipAddress: nil,
                deviceInfo: self.getDeviceInfo()
            )
            self.entries.append(entry)
            try? self.storage.save(self.entries, forKey: self.storageKey)
        }
    }
    
    private func getDeviceInfo() -> String {
        #if os(iOS)
        import UIKit
        return "\(UIDevice.current.model) - \(UIDevice.current.systemName) \(UIDevice.current.systemVersion)"
        #else
        return "Unknown Device"
        #endif
    }
    
    func getEntries(forAccountId accountId: String) -> [AuditEntry] {
        return entries.filter { $0.accountId == accountId }
    }
}

